// Extrae texto y chat_id del payload de Telegram (Telegram Trigger entrega el Update completo)
// v2.2: si el caso anterior ya se cerro y el cliente escribe NUEVO CASO, rota la sesion de memoria (epoch)
const body = $input.first().json;
const msg = body.message || body.edited_message || null;

if (!msg) {
  throw new Error('No se pudo ubicar el mensaje entrante en el payload de Telegram. Revisar formato del update.');
}

const chat_id = msg.chat.id;
const texto = msg.text || '';
const chatKey = String(chat_id);

const staticData = $getWorkflowStaticData('global');
staticData.captacion = staticData.captacion || {};
staticData.captacionEpoch = staticData.captacionEpoch || {};
let epoch = staticData.captacionEpoch[chatKey] || 1;

const previo = staticData.captacion[chatKey] || {};
const pideNuevoCaso = /^\s*(nuevo caso|nuevo|reiniciar|\/start)\s*$/i.test(texto);
if (pideNuevoCaso && previo._cerrado) {
  epoch += 1;
  staticData.captacionEpoch[chatKey] = epoch;
  delete staticData.captacion[chatKey];  // solo se limpia cuando el cliente pide explicitamente un caso nuevo
}

// epoch 1 conserva la clave historica tg_<chat_id>: la Simple Memory acumulada NO se pierde
const session_key = epoch === 1 ? `tg_${chat_id}` : `tg_${chat_id}_e${epoch}`;

return [{
  json: {
    chat_id,
    texto_mensaje: texto,
    message_id: msg.message_id,
    session_key,
  }
}];

// v2.1: el LLM solo extrae; el estado se acumula aca (workflowStaticData, por chat_id)
// y las preguntas al cliente las arma este codigo. Progreso garantizado por turno.
const input = $input.first().json;
const output = String(input.output || input.text || '');
const chat_id = $('Normalizar mensaje entrante').first().json.chat_id;
const chatKey = String(chat_id);

const requiredOrder = [
  'nombre_apellido_cliente',
  'dni',
  'telefono_whatsapp',
  'fecha_hora_hecho',
  'lugar_hecho',
  'vehiculo_propio',
  'hubo_lesiones',
];

const ALL_FIELDS = ['nombre_apellido_cliente','dni','telefono_whatsapp','email','nacionalidad',
  'grupo_familiar','profesion_especialidad_antiguedad','domicilio_laboral_bono_sueldo',
  'padre_madre_menor','fecha_hora_hecho','lugar_hecho','dependencia_policial','numero_sumario',
  'vehiculo_propio','aseguradora_propia','datos_tercero','aseguradora_tercero','hubo_lesiones',
  'detalle_lesiones','testigos','fotos_videos'];

const fieldQuestions = {
  nombre_apellido_cliente: 'Para empezar, decime tu nombre y apellido completo.',
  dni: 'Decime tu DNI, por favor.',
  telefono_whatsapp: 'Pasame un telefono o WhatsApp de contacto.',
  fecha_hora_hecho: 'Decime la fecha completa del accidente (dia, mes y anio) y la hora aproximada. Por ejemplo: 02/05/2026 a las 12:30.',
  lugar_hecho: 'Contame donde fue el accidente: calle, esquina y ciudad si los recordas.',
  vehiculo_propio: 'Contame en que te movias vos: tipo de vehiculo, marca/modelo, color y patente si tenia (bicicleta o a pie tambien vale).',
  hubo_lesiones: 'Ultima pregunta clave: hubo lesiones o atencion medica despues del accidente? (si/no)',
};

function tryParseJson(raw) {
  if (!raw) return null;
  const cleaned = String(raw).trim().replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  try { return JSON.parse(cleaned); } catch (e) { return null; }
}

// busca el ultimo objeto JSON valido con clave formulario en el texto
function findControl(text) {
  const results = [];
  for (let i = 0; i < text.length; i++) {
    if (text[i] !== '{') continue;
    let depth = 0, inString = false, escape = false;
    for (let j = i; j < text.length; j++) {
      const ch = text[j];
      if (escape) { escape = false; continue; }
      if (inString && ch === '\\') { escape = true; continue; }
      if (ch === '"') { inString = !inString; continue; }
      if (inString) continue;
      if (ch === '{') depth++;
      if (ch === '}') {
        depth--;
        if (depth === 0) {
          const parsed = tryParseJson(text.slice(i, j + 1));
          if (parsed && parsed.formulario) results.push(parsed);
          i = j;
          break;
        }
      }
    }
  }
  return results.length ? results[results.length - 1] : null;
}

function hasValue(v) {
  if (typeof v === 'boolean') return true;
  return v !== undefined && v !== null && String(v).trim() !== '';
}

// --- estado persistente por chat (sobrevive entre mensajes con el workflow Activo) ---
const staticData = $getWorkflowStaticData('global');
staticData.captacion = staticData.captacion || {};
const previo = staticData.captacion[chatKey] || {};

// FIX anti-loop: si el caso de este chat ya se cerro, NO se vuelve a registrar nada.
// La Simple Memory hace que el LLM re-extraiga todos los datos en cada mensaje posterior;
// sin esta guarda, cada respuesta del cliente disparaba de nuevo carpeta + fila + cita + confirmacion.
if (previo._cerrado) {
  return [{
    json: {
      chat_id,
      reply_text: 'Gracias por tu mensaje! Tu caso ya esta registrado y la cita quedo agendada. El estudio va a leer tu respuesta y te contesta a la brevedad. Si necesitas iniciar un caso nuevo, escribi: NUEVO CASO.',
      status: 'caso_cerrado',
      campos_faltantes: null,
      formulario: { campos: ALL_FIELDS.map(id => ({ id, value: previo[id] ?? null })) },
      parse_ok: true,
      parse_error: null,
      raw_output: output,
    }
  }];
}

const teniaDatosAntes = Object.keys(previo).filter(k => !k.startsWith('_')).some(k => hasValue(previo[k]));

const parsed = findControl(output) || tryParseJson(output);
let nuevosEsteTurno = 0;
if (parsed && parsed.formulario && Array.isArray(parsed.formulario.campos)) {
  for (const campo of parsed.formulario.campos) {
    const v = campo.value ?? campo.valor ?? null;
    if (hasValue(v)) {
      if (!hasValue(previo[campo.id]) || String(previo[campo.id]) !== String(v)) nuevosEsteTurno++;
      previo[campo.id] = v;  // el dato queda guardado aunque el modelo lo olvide despues
    }
  }
}
staticData.captacion[chatKey] = previo;

const missing = requiredOrder.filter(f => !hasValue(previo[f]));
const status = missing.length === 0 ? 'captacion_completa' : 'captacion_incompleta';

// --- mensaje al cliente: SIEMPRE deterministico (el LLM no redacta nada visible) ---
let visible;
if (status === 'captacion_completa') {
  visible = '';  // la confirmacion la envia el nodo de cierre con los datos de la cita
  previo._cerrado = true;  // marca el chat como cerrado: los proximos mensajes NO re-registran el caso
  previo._cerrado_en = new Date().toISOString();
  staticData.captacion[chatKey] = previo;  // los datos capturados quedan guardados; se reabre con NUEVO CASO
} else {
  const siguiente = fieldQuestions[missing[0]];
  if (!teniaDatosAntes && nuevosEsteTurno === 0) {
    visible = 'Hola! Soy Santiago, del Estudio Juridico TP Final. Lamento el accidente que tuviste. '
      + 'Te hago unas preguntas cortas para armar tu caso y coordinarte una cita presencial cuanto antes. '
      + siguiente;
  } else if (nuevosEsteTurno > 0) {
    visible = 'Anotado, gracias. ' + siguiente;
  } else {
    visible = 'Perdon, no llegue a registrar ese dato. ' + siguiente;
  }
}

// formulario consolidado para los nodos de cierre (Generar ID lee campos[].value)
const formulario = { campos: ALL_FIELDS.map(id => ({ id, value: previo[id] ?? null })) };

return [{
  json: {
    chat_id,
    reply_text: visible,
    status,
    campos_faltantes: missing.length ? missing : null,
    formulario,
    parse_ok: parsed !== null,
    parse_error: parsed ? null : 'El modelo no devolvio JSON; se re-pregunta deterministicamente.',
    raw_output: output,
  }
}];

// Arma caso_id y nombre de carpeta AAAA-MM-DD_Apellido_DNI a partir del formulario capturado
const campos = {};
for (const c of $json.formulario.campos) { campos[c.id] = c.value ?? c.valor ?? null; }

const hoy = new Date();
const fecha = hoy.toISOString().slice(0, 10);

const nombreCompleto = (campos.nombre_apellido_cliente || 'SinNombre').trim();
const apellido = nombreCompleto.split(' ').slice(-1)[0].replace(/[^a-zA-Z0-9]/g, '');
const dni = (campos.dni || 'SinDNI').replace(/[^0-9]/g, '');

const caso_id = `${fecha}_${apellido}_${dni}_${Math.random().toString(36).slice(2, 7)}`;
const nombre_carpeta = `${fecha}_${apellido}_${dni}`;

return [{
  json: {
    ...campos,
    caso_id,
    nombre_carpeta,
    fecha_captura: hoy.toISOString(),
    estado: 'Captación completa',
    chat_id: $('Normalizar mensaje entrante').first().json.chat_id,
  }
}];
